 1	import React from 'react';
 2	
 3	import { DataUpload } from '@kubevirt-utils/hooks/useCDIUpload/useCDIUpload';
 4	import {
 5	  UPLOAD_STATUS,
 6	  UPLOAD_STATUS_LABELS,
 7	  uploadStatusToProgressVariant,
 8	} from '@kubevirt-utils/hooks/useCDIUpload/utils';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import {
11	  Button,
12	  FormGroup,
13	  Progress,
14	  ProgressMeasureLocation,
15	  Stack,
16	  StackItem,
17	} from '@patternfly/react-core';
18	
19	export const DiskSourceUploadPVCProgress: React.FC<{ upload: DataUpload }> = ({ upload }) => {
20	  const { t } = useKubevirtTranslation();
21	  return (
22	    <FormGroup fieldId="upload-progress">
23	      <Stack hasGutter>
24	        <StackItem>
25	          <Progress
26	            measureLocation={ProgressMeasureLocation.inside}
27	            title={UPLOAD_STATUS_LABELS[upload?.uploadStatus]}
28	            value={upload?.progress}
29	            variant={uploadStatusToProgressVariant[upload?.uploadStatus]}
30	          />
31	        </StackItem>
32	        <StackItem>
33	          <Button
34	            isDisabled={
35	              upload?.uploadStatus === UPLOAD_STATUS.CANCELED ||
36	              upload?.uploadStatus === UPLOAD_STATUS.ERROR ||
37	              upload?.uploadStatus === UPLOAD_STATUS.SUCCESS
38	            }
39	            isInline
40	            onClick={() => upload?.cancelUpload()}
41	            variant="link"
42	          >
43	            {t('Cancel upload')}
44	          </Button>
45	        </StackItem>
46	      </Stack>
47	    </FormGroup>
48	  );
49	};

